package claudecode

import (
	"fmt"
	"os"
	"path"
	"path/filepath"
	"sort"
	"strings"

	"github.com/dayvidpham/pasture/internal/codegen"
)

// The embedded assets/ tree carries three Claude Code plugin packages. Two of
// them — pasture-skills and pasture-agents — carry codegen-driven files whose
// canonical source of truth is the live codegen pipeline (specs_data + templates
// rendered by codegen.EmitHarness for the claude-code target). Those files are
// regenerated by the go:generate directive in generate.go and are guarded
// against silent drift by TestEmbeddedAssetsMatchLivePipeline.
//
// The remaining embedded content — each package's .claude-plugin/plugin.json,
// the pasture-hooks package (hooks.json, bd-prime.md, scripts/), and the
// hand-authored verbatim skill trees (skills/protocol, skills/install-cli) — has
// no generator: it is authored directly in this slice's assets tree. The
// generated-file drift check deliberately does not manage those paths, so a
// change to plugin scaffolding never requires a codegen run.
const (
	// assetsDirName is the on-disk directory (relative to this package) that the
	// //go:embed all:assets directive captures.
	assetsDirName = "assets"

	// skillsPackageDir and agentsPackageDir are the two codegen-fed plugin
	// packages inside the embedded assets tree.
	skillsPackageDir = "pasture-skills"
	agentsPackageDir = "pasture-agents"
)

// verbatimSkillDirs are the top-level skill directories under
// pasture-skills/skills that are hand-authored (copied verbatim) rather than
// emitted by the claude-code codegen pipeline. They are excluded from the
// generated-file drift check because codegen.EmitHarness(ClaudeCodeTarget) does
// not emit them (the claude-code target declares no Verbatim trees).
var verbatimSkillDirs = map[string]struct{}{
	"protocol":    {},
	"install-cli": {},
}

// RenderGeneratedAssets renders, in memory, every codegen-driven Claude Code
// plugin file the embedded assets tree must carry, keyed by its assets-relative
// path (for example "pasture-skills/skills/worker/SKILL.md" or
// "pasture-agents/agents/reviewer.md").
//
// It drives the same live pipeline the repository's canonical skills/ and
// agents/ trees come from — codegen.EmitHarness for the pinned claude-code
// target — so the returned bytes are exactly what a fresh generation produces.
// repoRoot is the module root that contains the canonical skills/ and agents/
// trees; the claude-code target reads those (its skills are marker-merged) to
// produce full-file output. The result is the single source of truth shared by
// the asset generator (tools/claudecode-assets) and the drift test, so they can
// never disagree about what "correct" means.
func RenderGeneratedAssets(repoRoot string) (map[string][]byte, error) {
	const where = "claudecode.RenderGeneratedAssets"
	figuresDir := filepath.Join(repoRoot, "skills", "protocol", "figures")
	files, err := codegen.EmitHarness(
		repoRoot,
		codegen.ClaudeCodeTarget,
		figuresDir,
		codegen.GenerateOptions{Diff: false, Write: false},
	)
	if err != nil {
		return nil, fmt.Errorf(
			"%s: rendering the live claude-code codegen pipeline failed — "+
				"where: %s against module root %q — "+
				"why: the embedded plugin assets are derived from codegen.EmitHarness(ClaudeCodeTarget) output — "+
				"fix: run `make generate` so the canonical skills/ and agents/ trees are valid, then retry: %w",
			where, where, repoRoot, err,
		)
	}

	out := make(map[string][]byte, len(files))
	for _, file := range files {
		rel, err := filepath.Rel(repoRoot, file.Path)
		if err != nil {
			return nil, fmt.Errorf(
				"%s: generated file path %q is not under module root %q — "+
					"why: every claude-code file must be a module-relative path so it maps to an embedded package path — "+
					"fix: emit the claude-code target with the module root passed to RenderGeneratedAssets: %w",
				where, file.Path, repoRoot, err,
			)
		}
		rel = filepath.ToSlash(rel)

		var assetsRel string
		switch {
		case strings.HasPrefix(rel, "skills/"):
			assetsRel = skillsPackageDir + "/" + rel
		case strings.HasPrefix(rel, "agents/"):
			assetsRel = agentsPackageDir + "/" + rel
		default:
			return nil, fmt.Errorf(
				"%s: generated file %q is neither a skill nor an agent file — "+
					"why: the claude-code target is expected to emit only skills/<dir>/SKILL.md and agents/<role>.md, "+
					"which map to the pasture-skills and pasture-agents embedded packages — "+
					"fix: update RenderGeneratedAssets and the embedded package layout to cover this new output kind",
				where, rel,
			)
		}
		if _, clash := out[assetsRel]; clash {
			return nil, fmt.Errorf(
				"%s: two generated files map to the embedded path %q — "+
					"fix: emit each claude-code file exactly once", where, assetsRel)
		}
		out[assetsRel] = []byte(file.Content)
	}
	return out, nil
}

// isVerbatimSkillPath reports whether an assets-relative path lives under a
// hand-authored verbatim skill directory (skills/protocol or skills/install-cli)
// and is therefore not part of the codegen-driven, drift-checked surface.
func isVerbatimSkillPath(assetsRel string) bool {
	const prefix = skillsPackageDir + "/skills/"
	if !strings.HasPrefix(assetsRel, prefix) {
		return false
	}
	rest := strings.TrimPrefix(assetsRel, prefix)
	dir := rest
	if i := strings.IndexByte(rest, '/'); i >= 0 {
		dir = rest[:i]
	}
	_, ok := verbatimSkillDirs[dir]
	return ok
}

// FindModuleRootFrom walks upward from start until it finds the directory
// holding go.mod, returning that module (repository) root. The asset generator
// and the drift test both run with a working directory inside the module, so
// they can locate the canonical skills/ and agents/ trees this way without a
// hardcoded path.
func FindModuleRootFrom(start string) (string, error) {
	dir := start
	for {
		if _, err := os.Stat(filepath.Join(dir, "go.mod")); err == nil {
			return dir, nil
		}
		parent := filepath.Dir(dir)
		if parent == dir {
			return "", fmt.Errorf(
				"claudecode.FindModuleRootFrom: no go.mod found walking up from %q — "+
					"why: the asset generator and drift test locate the canonical skills/ and agents/ trees by finding the module root — "+
					"fix: run them from inside the pasture module",
				start,
			)
		}
		dir = parent
	}
}

// SortedAssetKeys returns the map's keys in lexicographic order, for
// deterministic iteration in the generator and test.
func SortedAssetKeys(m map[string][]byte) []string {
	keys := make([]string, 0, len(m))
	for k := range m {
		keys = append(keys, k)
	}
	sort.Strings(keys)
	return keys
}

// StaleGeneratedAssets walks the on-disk embedded assets directory and returns
// the absolute paths of every codegen-managed file the live pipeline no longer
// emits (its assets-relative path is absent from generated). It enumerates only
// the codegen-driven surface — generated SKILL.md leaves under non-verbatim
// skill directories and agent role files — so plugin scaffolding
// (.claude-plugin/plugin.json), the pasture-hooks package, and the verbatim
// skill trees are never reported and never removed. The generator uses this to
// prune a removed skill or renamed agent from the embed.
func StaleGeneratedAssets(assetsDir string, generated map[string][]byte) ([]string, error) {
	var stale []string
	for _, packageDir := range []string{skillsPackageDir, agentsPackageDir} {
		root := filepath.Join(assetsDir, packageDir)
		if _, err := os.Stat(root); os.IsNotExist(err) {
			continue
		}
		walkErr := filepath.WalkDir(root, func(p string, d os.DirEntry, err error) error {
			if err != nil {
				return err
			}
			if d.IsDir() {
				return nil
			}
			rel, relErr := filepath.Rel(assetsDir, p)
			if relErr != nil {
				return relErr
			}
			assetsRel := filepath.ToSlash(rel)
			if !isManagedGeneratedPath(packageDir, assetsRel) {
				return nil
			}
			if _, ok := generated[assetsRel]; !ok {
				stale = append(stale, p)
			}
			return nil
		})
		if walkErr != nil {
			return nil, fmt.Errorf(
				"claudecode.StaleGeneratedAssets: walking embedded package %q failed: %w", packageDir, walkErr)
		}
	}
	sort.Strings(stale)
	return stale, nil
}

// isManagedGeneratedPath reports whether an assets-relative path is a
// codegen-driven file the pipeline owns: a generated SKILL.md leaf outside the
// verbatim skill trees, or an agent role file outside the package's plugin
// scaffolding. It is the single predicate shared by the drift test's deletion
// guard and the generator's pruning step.
func isManagedGeneratedPath(packageDir, assetsRel string) bool {
	if packageDir == skillsPackageDir {
		return !isVerbatimSkillPath(assetsRel) && path.Base(assetsRel) == "SKILL.md"
	}
	return !strings.Contains(assetsRel, "/.claude-plugin/")
}
